#include<bits/stdc++.h>
using namespace std;
struct note{
    int p ,a;
    bool operator < (note f){
        return p < f.p;
    }
}f[2000006];
int main()
{
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= m; i++){
        cin >> f[i].p >> f[i].a;
    }
    sort(f + 1, f + m + 1);
    int ans = 0;
    for(int i = 0; i <= m; i++){
        if(n == 0){
            break;
        }else if(n - f[i].a >= 0){
            ans += f[i].a * f[i].p;
            n -= f[i].a;
        }else if(n - f[i].a < 0){
            ans += n * f[i].p;
            break;
        }
    }
    cout << ans;
}
